{
  "name": "DeviceRepairManager",
  "description": "Hệ thống quản lý bảo hành và sửa chữa thiết bị (Codec, Mic, Camera...) chuyên nghiệp."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DeviceType {
  CODEC = 'Codec',
  MIC = 'Mic',
  CAMERA = 'Camera',
  SOURCE = 'Nguồn',
  CONTROL = 'Điều khiển',
  OTHER = 'Khác'
}

export enum ShippingMethod {
  VIETTEL_POST = 'Viettel Post',
  TAXI = 'Taxi',
  BUS = 'Xe Buýt',
  DIRECT = 'Trực tiếp'
}

export enum RepairStatus {
  RECEIVED = 'Đã nhận',
  PROCESSING = 'Đang xử lý',
  RETURNED = 'Đã trả'
}

export interface Customer {
  id: string;
  fullName: string;
  organization: string; // Đơn vị
  phone: string;
  address: string;
  createdAt: number;
}

export interface RepairTicket {
  id: string;
  customerId: string;
  deviceType: DeviceType;
  deviceCondition: string; // Tình trạng
  receiveDate: string; // ISO Date string

  status: RepairStatus;

  // Output info
  returnDate?: string;
  returnNote?: string;
  shippingMethod?: ShippingMethod;

  createdAt: number;
  updatedAt: number;
}

// Stats interface for dashboard
export interface DashboardStats {
  totalTickets: number;
  processing: number;
  returned: number;
  received: number;
}

import { Customer, RepairTicket } from '../types';

const KEYS = {
  CUSTOMERS: 'drm_customers',
  TICKETS: 'drm_tickets'
};

export const StorageService = {
  getCustomers: (): Customer[] => {
    try {
      const data = localStorage.getItem(KEYS.CUSTOMERS);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Error loading customers", e);
      return [];
    }
  },

  saveCustomers: (customers: Customer[]) => {
    localStorage.setItem(KEYS.CUSTOMERS, JSON.stringify(customers));
  },

  getTickets: (): RepairTicket[] => {
    try {
      const data = localStorage.getItem(KEYS.TICKETS);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Error loading tickets", e);
      return [];
    }
  },

  saveTickets: (tickets: RepairTicket[]) => {
    localStorage.setItem(KEYS.TICKETS, JSON.stringify(tickets));
  }
};

import React from 'react';
import { LayoutDashboard, Users, Wrench, Package, Menu, X } from 'lucide-react';
import { Link, useLocation } from 'react-router-dom';

interface LayoutProps {
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const [isSidebarOpen, setIsSidebarOpen] = React.useState(false);
  const location = useLocation();

  const navItems = [
    { label: 'Tổng quan', path: '/', icon: <LayoutDashboard size={20} /> },
    { label: 'Quản lý sửa chữa', path: '/repairs', icon: <Wrench size={20} /> },
    { label: 'Khách hàng & Đơn vị', path: '/customers', icon: <Users size={20} /> },
  ];

  const isActive = (path: string) => location.pathname === path;

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-20 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside 
        className={`
          fixed lg:static inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white transform transition-transform duration-200 ease-in-out
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
        `}
      >
        <div className="flex items-center justify-between p-6 border-b border-slate-700">
          <div className="flex items-center space-x-2">
            <Package className="text-blue-500" size={28} />
            <span className="text-xl font-bold">DeviceMgr</span>
          </div>
          <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-white">
            <X size={24} />
          </button>
        </div>

        <nav className="p-4 space-y-2">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              onClick={() => setIsSidebarOpen(false)}
              className={`
                flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors
                ${isActive(item.path) 
                  ? 'bg-blue-600 text-white shadow-lg' 
                  : 'text-slate-300 hover:bg-slate-800 hover:text-white'}
              `}
            >
              {item.icon}
              <span className="font-medium">{item.label}</span>
            </Link>
          ))}
        </nav>

        <div className="absolute bottom-0 w-full p-6 border-t border-slate-800">
          <p className="text-xs text-slate-500">
            Phiên bản 1.0.0
            <br />
            © 2024 Admin System
          </p>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="bg-white shadow-sm z-10 p-4 lg:hidden flex items-center">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="p-2 rounded-md text-slate-600 hover:bg-slate-100"
          >
            <Menu size={24} />
          </button>
          <span className="ml-4 font-semibold text-slate-700">Menu</span>
        </header>

        <main className="flex-1 overflow-auto p-4 lg:p-8">
          <div className="max-w-7xl mx-auto">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Customer } from '../types';
import { StorageService } from '../services/storage';
import { Plus, Search, MapPin, Phone, Building2, Trash2, Edit2 } from 'lucide-react';

export const CustomersPage: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Customer>>({
    fullName: '',
    organization: '',
    phone: '',
    address: ''
  });

  useEffect(() => {
    setCustomers(StorageService.getCustomers());
  }, []);

  const handleSave = () => {
    if (!formData.fullName || !formData.organization) return alert('Vui lòng nhập tên và đơn vị');

    const newCustomer: Customer = {
      id: editingId || crypto.randomUUID(),
      fullName: formData.fullName!,
      organization: formData.organization!,
      phone: formData.phone || '',
      address: formData.address || '',
      createdAt: editingId ? (customers.find(c => c.id === editingId)?.createdAt || Date.now()) : Date.now()
    };

    let updatedList;
    if (editingId) {
      updatedList = customers.map(c => c.id === editingId ? newCustomer : c);
    } else {
      updatedList = [newCustomer, ...customers];
    }

    setCustomers(updatedList);
    StorageService.saveCustomers(updatedList);
    closeModal();
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa khách hàng này?')) {
      const updatedList = customers.filter(c => c.id !== id);
      setCustomers(updatedList);
      StorageService.saveCustomers(updatedList);
    }
  };

  const openModal = (customer?: Customer) => {
    if (customer) {
      setEditingId(customer.id);
      setFormData(customer);
    } else {
      setEditingId(null);
      setFormData({ fullName: '', organization: '', phone: '', address: '' });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const filteredCustomers = customers.filter(c => 
    c.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.organization.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Khách hàng & Đơn vị</h1>
          <p className="text-slate-500">Quản lý danh sách đơn vị và thông tin liên hệ</p>
        </div>
        <button 
          onClick={() => openModal()}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors shadow-sm"
        >
          <Plus size={18} />
          <span>Thêm mới</span>
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50">
          <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm kiếm theo tên, đơn vị..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-600 font-medium">
              <tr>
                <th className="px-6 py-3">Khách hàng / Đơn vị</th>
                <th className="px-6 py-3">Liên hệ</th>
                <th className="px-6 py-3">Địa chỉ</th>
                <th className="px-6 py-3 text-right">Thao tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredCustomers.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-6 py-8 text-center text-slate-500">
                    Chưa có dữ liệu khách hàng.
                  </td>
                </tr>
              ) : (
                filteredCustomers.map((customer) => (
                  <tr key={customer.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="font-semibold text-slate-900">{customer.fullName}</div>
                      <div className="flex items-center gap-1 text-slate-500 text-xs mt-1">
                        <Building2 size={12} />
                        {customer.organization}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2 text-slate-600">
                        <Phone size={14} className="text-slate-400" />
                        {customer.phone || '---'}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2 text-slate-600 max-w-xs truncate">
                        <MapPin size={14} className="text-slate-400" />
                        {customer.address || '---'}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end gap-2">
                        <button 
                          onClick={() => openModal(customer)}
                          className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => handleDelete(customer.id)}
                          className="p-1.5 text-red-600 hover:bg-red-50 rounded"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
            <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50">
              <h3 className="font-semibold text-lg text-slate-800">
                {editingId ? 'Cập nhật thông tin' : 'Thêm khách hàng mới'}
              </h3>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <div className="p-6 space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-sm font-medium text-slate-700">Họ và tên <span className="text-red-500">*</span></label>
                  <input 
                    type="text" 
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={formData.fullName}
                    onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                    placeholder="Nguyễn Văn A"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-sm font-medium text-slate-700">Đơn vị <span className="text-red-500">*</span></label>
                  <input 
                    type="text" 
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={formData.organization}
                    onChange={(e) => setFormData({...formData, organization: e.target.value})}
                    placeholder="Công ty XYZ"
                  />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Số điện thoại</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                  value={formData.phone}
                  onChange={(e) => setFormData({...formData, phone: e.target.value})}
                  placeholder="0987..."
                />
              </div>

              <div className="space-y-1">
                <label className="text-sm font-medium text-slate-700">Địa chỉ</label>
                <textarea 
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                  rows={3}
                  value={formData.address}
                  onChange={(e) => setFormData({...formData, address: e.target.value})}
                  placeholder="Số nhà, đường, quận/huyện..."
                />
              </div>
            </div>

            <div className="px-6 py-4 bg-slate-50 border-t border-slate-200 flex justify-end gap-3">
              <button 
                onClick={closeModal}
                className="px-4 py-2 text-slate-600 hover:bg-slate-200 rounded-lg transition-colors font-medium"
              >
                Hủy bỏ
              </button>
              <button 
                onClick={handleSave}
                className="px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg transition-colors font-medium shadow-sm"
              >
                Lưu thông tin
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Customer, RepairTicket, DeviceType, RepairStatus, ShippingMethod } from '../types';
import { StorageService } from '../services/storage';
import { Plus, Search, Filter, AlertCircle, CheckCircle2, Clock, Truck, ChevronRight, X } from 'lucide-react';

export const RepairsPage: React.FC = () => {
  const [tickets, setTickets] = useState<RepairTicket[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<RepairTicket>>({});

  useEffect(() => {
    setTickets(StorageService.getTickets());
    setCustomers(StorageService.getCustomers());
  }, []);

  const getCustomer = (id: string) => customers.find(c => c.id === id);

  const handleSave = () => {
    if (!formData.customerId || !formData.deviceType || !formData.receiveDate) {
      alert('Vui lòng điền đầy đủ thông tin bắt buộc');
      return;
    }

    // Logic to validate status changes
    if (formData.status === RepairStatus.RETURNED) {
      if (!formData.returnDate || !formData.shippingMethod) {
        alert('Khi trạng thái là "Đã trả", vui lòng nhập ngày trả và đơn vị vận chuyển.');
        return;
      }
    }

    const newTicket: RepairTicket = {
      id: editingId || crypto.randomUUID(),
      customerId: formData.customerId,
      deviceType: formData.deviceType,
      deviceCondition: formData.deviceCondition || 'Không rõ',
      receiveDate: formData.receiveDate,
      status: formData.status || RepairStatus.RECEIVED,

      returnDate: formData.returnDate,
      returnNote: formData.returnNote,
      shippingMethod: formData.shippingMethod,

      createdAt: editingId ? (tickets.find(t => t.id === editingId)?.createdAt || Date.now()) : Date.now(),
      updatedAt: Date.now()
    };

    let updatedList;
    if (editingId) {
      updatedList = tickets.map(t => t.id === editingId ? newTicket : t);
    } else {
      updatedList = [newTicket, ...tickets];
    }

    setTickets(updatedList);
    StorageService.saveTickets(updatedList);
    closeModal();
  };

  const openModal = (ticket?: RepairTicket) => {
    if (ticket) {
      setEditingId(ticket.id);
      setFormData({ ...ticket });
    } else {
      setEditingId(null);
      setFormData({
        status: RepairStatus.RECEIVED,
        receiveDate: new Date().toISOString().split('T')[0],
        deviceType: DeviceType.CODEC,
        deviceCondition: ''
      });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const statusColors = {
    [RepairStatus.RECEIVED]: 'bg-blue-100 text-blue-700 border-blue-200',
    [RepairStatus.PROCESSING]: 'bg-amber-100 text-amber-700 border-amber-200',
    [RepairStatus.RETURNED]: 'bg-green-100 text-green-700 border-green-200',
  };

  const statusIcons = {
    [RepairStatus.RECEIVED]: <AlertCircle size={14} />,
    [RepairStatus.PROCESSING]: <Clock size={14} />,
    [RepairStatus.RETURNED]: <CheckCircle2 size={14} />,
  };

  const filteredTickets = tickets.filter(t => {
    const customer = getCustomer(t.customerId);
    const matchesSearch = 
      customer?.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      customer?.organization.toLowerCase().includes(searchTerm.toLowerCase()) ||
      t.deviceType.toLowerCase().includes(searchTerm.toLowerCase()) ||
      t.id.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === 'ALL' || t.status === statusFilter;

    return matchesSearch && matchesStatus;
  });

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Quản lý Sửa chữa</h1>
          <p className="text-slate-500">Theo dõi quy trình nhận và trả thiết bị</p>
        </div>
        <button 
          onClick={() => openModal()}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors shadow-sm"
        >
          <Plus size={18} />
          <span>Tạo phiếu mới</span>
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        {/* Filters */}
        <div className="p-4 border-b border-slate-200 bg-slate-50 flex flex-col md:flex-row gap-4 justify-between">
          <div className="relative max-w-md w-full">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm theo khách hàng, thiết bị..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div className="flex items-center gap-2">
            <Filter size={18} className="text-slate-500" />
            <select 
              className="px-3 py-2 border border-slate-300 rounded-lg bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
            >
              <option value="ALL">Tất cả trạng thái</option>
              {Object.values(RepairStatus).map(s => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-600 font-medium">
              <tr>
                <th className="px-6 py-3">Mã phiếu / Ngày nhận</th>
                <th className="px-6 py-3">Khách hàng / Đơn vị</th>
                <th className="px-6 py-3">Thiết bị</th>
                <th className="px-6 py-3">Trạng thái</th>
                <th className="px-6 py-3">Thông tin trả</th>
                <th className="px-6 py-3 text-right">Chi tiết</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredTickets.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-500 flex flex-col items-center justify-center">
                    <WrenchIconPlaceholder />
                    <span className="mt-2">Chưa có phiếu sửa chữa nào.</span>
                  </td>
                </tr>
              ) : (
                filteredTickets.map((ticket) => {
                  const customer = getCustomer(ticket.customerId);
                  return (
                    <tr key={ticket.id} className="hover:bg-slate-50 transition-colors group cursor-pointer" onClick={() => openModal(ticket)}>
                      <td className="px-6 py-4">
                        <div className="font-mono text-xs text-slate-400">#{ticket.id.slice(0, 8)}</div>
                        <div className="font-medium text-slate-900 mt-1">{ticket.receiveDate}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="font-semibold text-slate-900">{customer?.fullName || 'Unknown'}</div>
                        <div className="text-slate-500 text-xs mt-1">{customer?.organization}</div>
                      </td>
                      <td className="px-6 py-4">
                        <span className="inline-flex items-center px-2 py-1 rounded bg-slate-100 text-slate-700 border border-slate-200 text-xs font-medium">
                          {ticket.deviceType}
                        </span>
                        <div className="text-slate-500 text-xs mt-1 max-w-[150px] truncate" title={ticket.deviceCondition}>
                          {ticket.deviceCondition}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border ${statusColors[ticket.status]}`}>
                          {statusIcons[ticket.status]}
                          {ticket.status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        {ticket.status === RepairStatus.RETURNED ? (
                          <div className="text-xs">
                            <div className="flex items-center gap-1 text-slate-700 font-medium">
                              <Truck size={12} />
                              {ticket.shippingMethod}
                            </div>
                            <div className="text-slate-500 mt-0.5">{ticket.returnDate}</div>
                          </div>
                        ) : (
                          <span className="text-slate-400 text-xs italic">Chưa trả</span>
                        )}
                      </td>
                      <td className="px-6 py-4 text-right">
                        <ChevronRight className="inline-block text-slate-300 group-hover:text-blue-500 transition-colors" size={20} />
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal Form */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl my-8 flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50 rounded-t-xl sticky top-0">
              <h3 className="font-semibold text-lg text-slate-800">
                {editingId ? 'Cập nhật Phiếu Sửa Chữa' : 'Tạo Phiếu Mới'}
              </h3>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <div className="p-6 overflow-y-auto space-y-6">
              {/* Customer Section */}
              <div className="space-y-4">
                <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wider border-b pb-2">Thông tin nhận</h4>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Khách hàng <span className="text-red-500">*</span></label>
                    <select 
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white"
                      value={formData.customerId || ''}
                      onChange={(e) => setFormData({...formData, customerId: e.target.value})}
                      disabled={customers.length === 0}
                    >
                      <option value="">-- Chọn khách hàng --</option>
                      {customers.map(c => (
                        <option key={c.id} value={c.id}>{c.fullName} - {c.organization}</option>
                      ))}
                    </select>
                    {customers.length === 0 && (
                      <p className="text-xs text-red-500 mt-1">Vui lòng tạo khách hàng trước.</p>
                    )}
                  </div>

                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Ngày nhận <span className="text-red-500">*</span></label>
                    <input 
                      type="date" 
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                      value={formData.receiveDate || ''}
                      onChange={(e) => setFormData({...formData, receiveDate: e.target.value})}
                    />
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Loại thiết bị <span className="text-red-500">*</span></label>
                    <select 
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white"
                      value={formData.deviceType || DeviceType.CODEC}
                      onChange={(e) => setFormData({...formData, deviceType: e.target.value as DeviceType})}
                    >
                      {Object.values(DeviceType).map(t => (
                        <option key={t} value={t}>{t}</option>
                      ))}
                    </select>
                  </div>

                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Tình trạng khi nhận</label>
                    <input 
                      type="text" 
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                      value={formData.deviceCondition || ''}
                      onChange={(e) => setFormData({...formData, deviceCondition: e.target.value})}
                      placeholder="VD: Không lên nguồn, vỡ kính..."
                    />
                  </div>
                </div>
              </div>

              {/* Status Section */}
              <div className="space-y-4">
                <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wider border-b pb-2">Xử lý & Trả hàng</h4>

                <div className="space-y-1">
                  <label className="text-sm font-medium text-slate-700">Trạng thái hiện tại</label>
                  <div className="flex gap-4">
                     {Object.values(RepairStatus).map((status) => (
                       <label key={status} className={`
                          flex-1 flex items-center justify-center gap-2 p-3 rounded-lg border cursor-pointer transition-all
                          ${formData.status === status 
                            ? 'bg-blue-50 border-blue-500 text-blue-700 ring-1 ring-blue-500' 
                            : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}
                       `}>
                         <input 
                           type="radio" 
                           name="status" 
                           value={status}
                           checked={formData.status === status}
                           onChange={(e) => setFormData({...formData, status: e.target.value as RepairStatus})}
                           className="hidden"
                         />
                         <span className="font-medium text-sm">{status}</span>
                       </label>
                     ))}
                  </div>
                </div>

                {/* Conditional Fields for RETURNED status */}
                {formData.status === RepairStatus.RETURNED && (
                  <div className="bg-green-50 p-4 rounded-lg border border-green-100 space-y-4 animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-start gap-2 text-green-800 text-sm mb-2">
                      <Truck size={16} className="mt-0.5" />
                      <span>Thông tin người nhận sẽ được lấy tự động từ dữ liệu khách hàng.</span>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                       <div className="space-y-1">
                        <label className="text-sm font-medium text-slate-700">Ngày trả <span className="text-red-500">*</span></label>
                        <input 
                          type="date" 
                          className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:outline-none"
                          value={formData.returnDate || new Date().toISOString().split('T')[0]}
                          onChange={(e) => setFormData({...formData, returnDate: e.target.value})}
                        />
                      </div>

                      <div className="space-y-1">
                        <label className="text-sm font-medium text-slate-700">Đơn vị vận chuyển <span className="text-red-500">*</span></label>
                        <select 
                          className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:outline-none bg-white"
                          value={formData.shippingMethod || ShippingMethod.VIETTEL_POST}
                          onChange={(e) => setFormData({...formData, shippingMethod: e.target.value as ShippingMethod})}
                        >
                           {Object.values(ShippingMethod).map(m => (
                            <option key={m} value={m}>{m}</option>
                          ))}
                        </select>
                      </div>
                    </div>

                    <div className="space-y-1">
                      <label className="text-sm font-medium text-slate-700">Ghi chú trả hàng</label>
                      <textarea 
                        className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:outline-none"
                        rows={2}
                        value={formData.returnNote || ''}
                        onChange={(e) => setFormData({...formData, returnNote: e.target.value})}
                        placeholder="VD: Đã thay main, kèm dây nguồn..."
                      />
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div className="px-6 py-4 bg-slate-50 border-t border-slate-200 flex justify-end gap-3 rounded-b-xl sticky bottom-0">
              <button 
                onClick={closeModal}
                className="px-4 py-2 text-slate-600 hover:bg-slate-200 rounded-lg transition-colors font-medium"
              >
                Hủy bỏ
              </button>
              <button 
                onClick={handleSave}
                className="px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg transition-colors font-medium shadow-sm"
              >
                Lưu Phiếu
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

