import React, { useEffect, useState } from 'react';
import { StorageService } from '../services/storage';
import { RepairStatus } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import { CheckCircle2, Clock, AlertCircle, Package } from 'lucide-react';

export const DashboardPage: React.FC = () => {
  const [stats, setStats] = useState({
    total: 0,
    received: 0,
    processing: 0,
    returned: 0
  });

  useEffect(() => {
    const tickets = StorageService.getTickets();
    setStats({
      total: tickets.length,
      received: tickets.filter(t => t.status === RepairStatus.RECEIVED).length,
      processing: tickets.filter(t => t.status === RepairStatus.PROCESSING).length,
      returned: tickets.filter(t => t.status === RepairStatus.RETURNED).length,
    });
  }, []);

  const data = [
    { name: 'Đang xử lý', value: stats.processing, color: '#f59e0b' },
    { name: 'Đã nhận', value: stats.received, color: '#3b82f6' },
    { name: 'Đã trả', value: stats.returned, color: '#22c55e' },
  ];

  return (
    <div className="space-y-6">
       <div>
          <h1 className="text-2xl font-bold text-slate-900">Tổng quan Hệ thống</h1>
          <p className="text-slate-500">Báo cáo tình trạng xử lý thiết bị</p>
        </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          title="Tổng phiếu" 
          value={stats.total} 
          icon={<Package className="text-slate-600" />} 
          bg="bg-slate-100" 
        />
        <StatCard 
          title="Đã nhận" 
          value={stats.received} 
          icon={<AlertCircle className="text-blue-600" />} 
          bg="bg-blue-50" 
          borderColor="border-blue-200"
        />
        <StatCard 
          title="Đang xử lý" 
          value={stats.processing} 
          icon={<Clock className="text-amber-600" />} 
          bg="bg-amber-50" 
          borderColor="border-amber-200"
        />
        <StatCard 
          title="Đã hoàn thành" 
          value={stats.returned} 
          icon={<CheckCircle2 className="text-green-600" />} 
          bg="bg-green-50" 
          borderColor="border-green-200"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 min-h-[300px]">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Biểu đồ trạng thái</h3>
          {stats.total === 0 ? (
            <div className="h-64 flex items-center justify-center text-slate-400">
              Chưa có dữ liệu
            </div>
          ) : (
            <ResponsiveContainer width="100%" height={300}>
              <PieChart>
                <Pie
                  data={data}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          )}
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Hướng dẫn nhanh</h3>
          <ul className="space-y-4">
             <li className="flex gap-3">
               <div className="flex-shrink-0 w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-bold text-sm">1</div>
               <div>
                 <p className="font-medium text-slate-900">Tạo Khách hàng</p>
                 <p className="text-sm text-slate-500">Vào mục "Khách hàng" để thêm đơn vị mới trước khi tạo phiếu sửa chữa.</p>
               </div>
             </li>
             <li className="flex gap-3">
               <div className="flex-shrink-0 w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-bold text-sm">2</div>
               <div>
                 <p className="font-medium text-slate-900">Tiếp nhận Thiết bị</p>
                 <p className="text-sm text-slate-500">Tạo phiếu mới, chọn loại thiết bị (Codec, Mic...) và ghi nhận tình trạng.</p>
               </div>
             </li>
             <li className="flex gap-3">
               <div className="flex-shrink-0 w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-bold text-sm">3</div>
               <div>
                 <p className="font-medium text-slate-900">Trả thiết bị</p>
                 <p className="text-sm text-slate-500">Cập nhật trạng thái thành "Đã trả", hệ thống sẽ yêu cầu nhập thông tin vận chuyển.</p>
               </div>
             </li>
          </ul>
        </div>
      </div>
    </div>
  );
};

