export enum DeviceType {
  CODEC = 'Codec',
  MIC = 'Mic',
  CAMERA = 'Camera',
  SOURCE = 'Nguồn',
  CONTROL = 'Điều khiển',
  OTHER = 'Khác'
}

export enum ShippingMethod {
  VIETTEL_POST = 'Viettel Post',
  TAXI = 'Taxi',
  BUS = 'Xe Buýt',
  DIRECT = 'Trực tiếp'
}

export enum RepairStatus {
  RECEIVED = 'Đã nhận',
  PROCESSING = 'Đang xử lý',
  RETURNED = 'Đã trả'
}

export enum WarrantyStatus {
  SENT = 'Đã gửi hãng',
  FIXING = 'Đang sửa',
  DONE = 'Đã xong',
  CANNOT_FIX = 'Không sửa được'
}

export interface Organization {
  id: string;
  name: string;
  address: string;
  createdAt: number;
}

export interface Customer {
  id: string;
  fullName: string;
  organizationId: string; // Changed from free text to ID reference
  phone: string;
  address: string;
  createdAt: number;
}

export interface RepairTicket {
  id: string;
  customerId: string;
  deviceType: DeviceType;
  serialNumber?: string; // Added for device history tracking
  deviceCondition: string; // Tình trạng
  receiveDate: string; // ISO Date string

  status: RepairStatus;

  // Output info
  returnDate?: string;
  returnNote?: string;
  shippingMethod?: ShippingMethod;

  createdAt: number;
  updatedAt: number;
}

export interface WarrantyTicket {
  id: string;
  organizationId: string; // ID của Đơn vị (Hãng/Trung tâm sửa chữa)
  deviceType: DeviceType;
  serialNumber?: string;
  description: string; // Mô tả lỗi/Tình trạng
  sentDate: string;

  status: WarrantyStatus;

  returnDate?: string;
  cost?: number; // Chi phí sửa chữa
  note?: string; // Ghi chú thêm

  createdAt: number;
  updatedAt: number;
}

// Stats interface for dashboard
export interface DashboardStats {
  totalTickets: number;
  processing: number;
  returned: number;
  received: number;
}

import { Customer, RepairTicket, Organization, WarrantyTicket } from '../types';

const KEYS = {
  CUSTOMERS: 'drm_customers',
  TICKETS: 'drm_tickets',
  ORGANIZATIONS: 'drm_organizations',
  WARRANTIES: 'drm_warranties'
};

export const StorageService = {
  getOrganizations: (): Organization[] => {
    try {
      const data = localStorage.getItem(KEYS.ORGANIZATIONS);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Error loading organizations", e);
      return [];
    }
  },

  saveOrganizations: (orgs: Organization[]) => {
    localStorage.setItem(KEYS.ORGANIZATIONS, JSON.stringify(orgs));
  },

  getCustomers: (): Customer[] => {
    try {
      const data = localStorage.getItem(KEYS.CUSTOMERS);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Error loading customers", e);
      return [];
    }
  },

  saveCustomers: (customers: Customer[]) => {
    localStorage.setItem(KEYS.CUSTOMERS, JSON.stringify(customers));
  },

  getTickets: (): RepairTicket[] => {
    try {
      const data = localStorage.getItem(KEYS.TICKETS);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Error loading tickets", e);
      return [];
    }
  },

  saveTickets: (tickets: RepairTicket[]) => {
    localStorage.setItem(KEYS.TICKETS, JSON.stringify(tickets));
  },

  getWarrantyTickets: (): WarrantyTicket[] => {
    try {
      const data = localStorage.getItem(KEYS.WARRANTIES);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Error loading warranties", e);
      return [];
    }
  },

  saveWarrantyTickets: (tickets: WarrantyTicket[]) => {
    localStorage.setItem(KEYS.WARRANTIES, JSON.stringify(tickets));
  }
};

