// components/DeviceIcon.tsx
import React from 'react';
import { Cpu, Mic, Video, Zap, Tablet, Server } from 'lucide-react';
import { DeviceType } from '@/types';

interface DeviceIconProps {
  type: DeviceType | string | null | undefined;
  size?: number;
  className?: string;
}

const DeviceIcon: React.FC<DeviceIconProps> = ({ type, size = 20, className }) => {
  let icon: React.FC<any> | null = null;

  switch (type) {
    case DeviceType.CODEC:
    case 'Codec':
    case 'Bộ giải mã':
      icon = Server;
      break;
    case DeviceType.MIC:
    case 'Mic':
    case 'Micro':
      icon = Mic;
      break;
    case DeviceType.CAMERA:
    case 'Camera':
    case 'Máy ảnh':
      icon = Video;
      break;
    case DeviceType.POWER:
    case 'Nguồn':
    case 'Nguồn (Power)':
      icon = Zap;
      break;
    case DeviceType.CONTROL:
    case 'Control':
    case 'Điều khiển':
      icon = Tablet;
      break;
    default:
      icon = null;
  }

  return icon ? <icon size={size} className={className} /> : null;
};

export default DeviceIcon;
