import React, { useState, useEffect } from 'react';
import { WarrantyTicket, WarrantyStatus, Organization, DeviceType } from '../types';
import { StorageService } from '../services/storage';
import { Plus, Search, Filter, AlertCircle, CheckCircle2, Clock, Truck, ChevronRight, X, ChevronLeft, Building2, Coins, Download, Loader2 } from 'lucide-react';
import { DeviceIcon } from '../components/DeviceIcon';

export const WarrantyPage: React.FC = () => {
  const [tickets, setTickets] = useState<WarrantyTicket[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const ITEMS_PER_PAGE = 10;

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<WarrantyTicket>>({});

  const fetchData = async () => {
    setIsLoading(true);
    const [t, o] = await Promise.all([
      StorageService.getWarrantyTickets(),
      StorageService.getOrganizations()
    ]);
    setTickets(t);
    setOrganizations(o);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Reset page when filter changes
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter]);

  const getOrgName = (orgId: string) => {
    const org = organizations.find(o => o.id === orgId);
    return org ? org.name : 'Đơn vị không xác định';
  };

  // --- EXPORT FUNCTIONALITY ---
  const handleExport = () => {
    // 1. Prepare Header
    const headers = [
      "Mã Phiếu", 
      "Ngày Gửi", 
      "Đơn Vị Nhận (Hãng)", 
      "Loại Thiết Bị", 
      "Số Serial", 
      "Mô Tả Lỗi", 
      "Trạng Thái", 
      "Ngày Nhận Lại", 
      "Chi Phí", 
      "Ghi Chú"
    ];

    // 2. Prepare Rows
    // Sort for export as well? Usually good practice to match view.
    const sortedForExport = [...tickets].sort((a, b) => b.sentDate.localeCompare(a.sentDate));

    const rows = sortedForExport.map(t => {
      return [
        t.id.slice(0, 8),
        t.sentDate,
        getOrgName(t.organizationId),
        t.deviceType,
        t.serialNumber || '',
        t.description || '',
        t.status,
        t.returnDate || '',
        t.cost ? t.cost.toString() : '0',
        t.note || ''
      ].map(field => `"${field}"`).join(','); // Quote fields and join with comma
    });

    // 3. Combine with BOM for UTF-8 support
    const csvContent = "\uFEFF" + [headers.join(','), ...rows].join('\n');

    // 4. Create Blob and Link
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `Bao_cao_gui_hang_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSave = async () => {
    if (!formData.organizationId || !formData.deviceType || !formData.sentDate) {
      alert('Vui lòng điền đầy đủ thông tin: Đơn vị, Loại thiết bị, Ngày gửi');
      return;
    }

    const newTicket: WarrantyTicket = {
      id: editingId || crypto.randomUUID(),
      organizationId: formData.organizationId,
      deviceType: formData.deviceType,
      serialNumber: formData.serialNumber,
      description: formData.description || '',
      sentDate: formData.sentDate,
      status: formData.status || WarrantyStatus.SENT,

      returnDate: formData.returnDate,
      cost: formData.cost,
      note: formData.note,

      createdAt: editingId ? (tickets.find(t => t.id === editingId)?.createdAt || Date.now()) : Date.now(),
      updatedAt: Date.now()
    };

    try {
      if (editingId) {
        await StorageService.updateWarrantyTicket(newTicket);
      } else {
        await StorageService.addWarrantyTicket(newTicket);
      }
      await fetchData();
      closeModal();
    } catch (e) {
      console.error(e);
      alert('Lỗi khi lưu phiếu bảo hành');
    }
  };

  const openModal = (ticket?: WarrantyTicket) => {
    if (ticket) {
      setEditingId(ticket.id);
      setFormData({ ...ticket });
    } else {
      setEditingId(null);
      setFormData({
        status: WarrantyStatus.SENT,
        sentDate: new Date().toISOString().split('T')[0],
        deviceType: DeviceType.CODEC,
        description: '',
        serialNumber: ''
      });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa phiếu này?')) {
      try {
        await StorageService.deleteWarrantyTicket(id);
        await fetchData();
      } catch (e) {
        console.error(e);
        alert('Lỗi khi xóa phiếu');
      }
    }
  };

  const statusColors = {
    [WarrantyStatus.SENT]: 'bg-blue-100 text-blue-700 border-blue-200',
    [WarrantyStatus.FIXING]: 'bg-amber-100 text-amber-700 border-amber-200',
    [WarrantyStatus.DONE]: 'bg-green-100 text-green-700 border-green-200',
    [WarrantyStatus.CANNOT_FIX]: 'bg-red-100 text-red-700 border-red-200',
  };

  const filteredTickets = tickets.filter(t => {
    const orgName = getOrgName(t.organizationId);

    const matchesSearch = 
      orgName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      t.deviceType.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (t.serialNumber && t.serialNumber.toLowerCase().includes(searchTerm.toLowerCase())) ||
      t.id.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === 'ALL' || t.status === statusFilter;

    return matchesSearch && matchesStatus;
  }).sort((a, b) => b.sentDate.localeCompare(a.sentDate)); // Sort by date descending (newest first)

  // Pagination Logic
  const totalPages = Math.ceil(filteredTickets.length / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const paginatedTickets = filteredTickets.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Gửi Hãng / Bảo hành</h1>
          <p className="text-slate-500">Quản lý thiết bị gửi đi sửa chữa tại các hãng, đơn vị bên ngoài</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleExport}
            className="flex items-center gap-2 bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-4 py-2 rounded-lg transition-colors shadow-sm"
          >
            <Download size={18} />
            <span>Xuất Excel</span>
          </button>
          <button 
            onClick={() => openModal()}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors shadow-sm"
          >
            <Plus size={18} />
            <span>Tạo phiếu gửi</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
        {/* Filters */}
        <div className="p-4 border-b border-slate-200 bg-slate-50 flex flex-col md:flex-row gap-4 justify-between">
          <div className="relative max-w-md w-full">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm theo Serial, đơn vị, mã phiếu..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div className="flex items-center gap-2">
            <Filter size={18} className="text-slate-500" />
            <select 
              className="px-3 py-2 border border-slate-300 rounded-lg bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
            >
              <option value="ALL">Tất cả trạng thái</option>
              {Object.values(WarrantyStatus).map(s => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto min-h-[400px]">
          {isLoading ? (
             <div className="flex justify-center py-12">
               <Loader2 className="animate-spin text-blue-600" size={32} />
             </div>
          ) : (
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-600 font-medium">
              <tr>
                <th className="px-6 py-3">Mã phiếu / Ngày gửi</th>
                <th className="px-6 py-3">Gửi tới Đơn vị</th>
                <th className="px-6 py-3">Thiết bị</th>
                <th className="px-6 py-3">Mô tả / Ghi chú</th>
                <th className="px-6 py-3">Trạng thái</th>
                <th className="px-6 py-3">Ngày về / Chi phí</th>
                <th className="px-6 py-3 text-right">Thao tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {paginatedTickets.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-500">
                     <div className="flex flex-col items-center">
                        <Truck size={48} className="text-slate-200 mb-2" />
                        <span>Chưa có phiếu gửi hàng nào.</span>
                     </div>
                  </td>
                </tr>
              ) : (
                paginatedTickets.map((ticket) => {
                  return (
                    <tr key={ticket.id} className="hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => openModal(ticket)}>
                      {/* Cột 1: Mã + Ngày Gửi */}
                      <td className="px-6 py-4">
                        <div className="font-mono text-xs text-slate-400">#{ticket.id.slice(0, 8)}</div>
                        <div className="font-medium text-slate-900 mt-1 flex items-center gap-1">
                           <Clock size={12} className="text-blue-500"/> {ticket.sentDate}
                        </div>
                      </td>

                      {/* Cột 2: Đơn vị */}
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                           <Building2 size={16} className="text-slate-400" />
                           <span className="font-semibold text-slate-900">{getOrgName(ticket.organizationId)}</span>
                        </div>
                      </td>

                      {/* Cột 3: Thiết bị */}
                      <td className="px-6 py-4">
                        <div className="flex flex-col">
                           <div className="flex items-center gap-2">
                              <DeviceIcon type={ticket.deviceType} size={16} className="text-slate-500" />
                              <span className="font-medium text-slate-800">{ticket.deviceType}</span>
                           </div>
                          {ticket.serialNumber && (
                             <span className="text-xs font-mono text-slate-600 bg-slate-50 px-1 rounded border border-slate-100 w-fit mt-1 ml-6">
                              SN: {ticket.serialNumber}
                            </span>
                          )}
                        </div>
                      </td>

                      {/* Cột 4: Mô tả */}
                      <td className="px-6 py-4">
                         <div className="max-w-[150px] truncate text-slate-600" title={ticket.description}>
                            {ticket.description}
                         </div>
                      </td>

                      {/* Cột 5: Trạng Thái */}
                      <td className="px-6 py-4">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border ${statusColors[ticket.status]}`}>
                          {ticket.status}
                        </span>
                      </td>

                      {/* Cột 6: Ngày Về / Chi phí */}
                      <td className="px-6 py-4">
                        {ticket.returnDate ? (
                          <div className="text-xs">
                             <div className="flex items-center gap-1 font-medium text-green-700 mb-1">
                                <CheckCircle2 size={12} />
                                {ticket.returnDate}
                             </div>
                             {ticket.cost ? (
                                <div className="flex items-center gap-1 text-slate-600 font-mono">
                                  <Coins size={12} />
                                  {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(ticket.cost)}
                                </div>
                             ) : null}
                          </div>
                        ) : (
                          <span className="text-slate-400 text-xs italic">---</span>
                        )}
                      </td>

                      {/* Cột 7: Thao tác */}
                      <td className="px-6 py-4 text-right">
                        <ChevronRight className="text-slate-300 ml-auto" size={20} />
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
          )}
        </div>

        {/* Pagination Footer */}
        {filteredTickets.length > 0 && (
          <div className="px-6 py-4 border-t border-slate-200 bg-slate-50 flex items-center justify-between">
            <div className="text-sm text-slate-500">
              Hiển thị <span className="font-medium">{startIndex + 1}</span> đến <span className="font-medium">{Math.min(startIndex + ITEMS_PER_PAGE, filteredTickets.length)}</span> trong tổng số <span className="font-medium">{filteredTickets.length}</span> phiếu
            </div>
            <div className="flex items-center gap-2">
              <button 
                onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                disabled={currentPage === 1}
                className="p-2 border border-slate-300 rounded-lg hover:bg-white disabled:opacity-50 disabled:cursor-not-allowed bg-white text-slate-600 transition-colors"
              >
                <ChevronLeft size={16} />
              </button>
              <div className="px-4 py-1.5 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700">
                Trang {currentPage} / {totalPages || 1}
              </div>
              <button 
                onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                disabled={currentPage === totalPages || totalPages === 0}
                className="p-2 border border-slate-300 rounded-lg hover:bg-white disabled:opacity-50 disabled:cursor-not-allowed bg-white text-slate-600 transition-colors"
              >
                <ChevronRight size={16} />
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Modal Form */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl my-8 flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50 rounded-t-xl sticky top-0">
              <h3 className="font-semibold text-lg text-slate-800">
                {editingId ? 'Cập nhật Phiếu Gửi Hãng' : 'Tạo Phiếu Gửi Mới'}
              </h3>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <div className="p-6 overflow-y-auto space-y-6">
              <div className="space-y-4">
                <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wider border-b pb-2">Thông tin gửi</h4>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Đơn vị nhận (Hãng/Trung tâm) <span className="text-red-500">*</span></label>
                    <select 
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white"
                      value={formData.organizationId || ''}
                      onChange={(e) => setFormData({...formData, organizationId: e.target.value})}
                    >
                      <option value="">-- Chọn đơn vị --</option>
                      {organizations.map(org => (
                        <option key={org.id} value={org.id}>{org.name}</option>
                      ))}
                    </select>
                    {organizations.length === 0 && (
                      <p className="text-xs text-red-500 mt-1">Vui lòng tạo danh sách đơn vị trước.</p>
                    )}
                  </div>

                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Ngày gửi <span className="text-red-500">*</span></label>
                    <input 
                      type="date" 
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                      value={formData.sentDate || ''}
                      onChange={(e) => setFormData({...formData, sentDate: e.target.value})}
                    />
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Loại thiết bị <span className="text-red-500">*</span></label>
                    <select 
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white"
                      value={formData.deviceType || DeviceType.CODEC}
                      onChange={(e) => setFormData({...formData, deviceType: e.target.value as DeviceType})}
                    >
                      {Object.values(DeviceType).map(t => (
                        <option key={t} value={t}>{t}</option>
                      ))}
                    </select>
                  </div>

                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Số Serial / Model</label>
                    <input 
                      type="text" 
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                      value={formData.serialNumber || ''}
                      onChange={(e) => setFormData({...formData, serialNumber: e.target.value})}
                      placeholder="VD: SN12345678"
                    />
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-sm font-medium text-slate-700">Mô tả lỗi / Tình trạng</label>
                  <textarea 
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    rows={2}
                    value={formData.description || ''}
                    onChange={(e) => setFormData({...formData, description: e.target.value})}
                    placeholder="VD: Hỏng nguồn, cần thay main..."
                  />
                </div>
              </div>

              {/* Status Section */}
              <div className="space-y-4">
                <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wider border-b pb-2">Theo dõi & Kết quả</h4>

                <div className="space-y-1">
                  <label className="text-sm font-medium text-slate-700">Trạng thái hiện tại</label>
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                     {Object.values(WarrantyStatus).map((status) => (
                       <label key={status} className={`
                          flex flex-col items-center justify-center gap-1 p-2 rounded-lg border cursor-pointer transition-all text-center
                          ${formData.status === status 
                            ? 'bg-blue-50 border-blue-500 text-blue-700 ring-1 ring-blue-500' 
                            : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}
                       `}>
                         <input 
                           type="radio" 
                           name="status" 
                           value={status}
                           checked={formData.status === status}
                           onChange={(e) => setFormData({...formData, status: e.target.value as WarrantyStatus})}
                           className="hidden"
                         />
                         <span className="font-medium text-xs sm:text-sm">{status}</span>
                       </label>
                     ))}
                  </div>
                </div>

                {/* Conditional Fields for DONE status */}
                {(formData.status === WarrantyStatus.DONE || formData.status === WarrantyStatus.CANNOT_FIX) && (
                  <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 space-y-4 animate-in fade-in slide-in-from-top-2">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                       <div className="space-y-1">
                        <label className="text-sm font-medium text-slate-700">Ngày nhận lại</label>
                        <input 
                          type="date" 
                          className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                          value={formData.returnDate || new Date().toISOString().split('T')[0]}
                          onChange={(e) => setFormData({...formData, returnDate: e.target.value})}
                        />
                      </div>

                      <div className="space-y-1">
                        <label className="text-sm font-medium text-slate-700">Chi phí (VNĐ)</label>
                         <input 
                          type="number" 
                          className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                          value={formData.cost || ''}
                          onChange={(e) => setFormData({...formData, cost: Number(e.target.value)})}
                          placeholder="0"
                        />
                      </div>
                    </div>

                    <div className="space-y-1">
                      <label className="text-sm font-medium text-slate-700">Ghi chú thêm</label>
                      <textarea 
                        className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                        rows={2}
                        value={formData.note || ''}
                        onChange={(e) => setFormData({...formData, note: e.target.value})}
                        placeholder="VD: Đã thanh toán, bảo hành 3 tháng..."
                      />
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div className="px-6 py-4 bg-slate-50 border-t border-slate-200 flex justify-between rounded-b-xl sticky bottom-0">
               {editingId ? (
                 <button 
                  onClick={() => handleDelete(editingId)}
                  className="px-4 py-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors font-medium"
                >
                  Xóa phiếu
                </button>
               ) : <div></div>}

               <div className="flex gap-3">
                  <button 
                    onClick={closeModal}
                    className="px-4 py-2 text-slate-600 hover:bg-slate-200 rounded-lg transition-colors font-medium"
                  >
                    Hủy bỏ
                  </button>
                  <button 
                    onClick={handleSave}
                    className="px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg transition-colors font-medium shadow-sm"
                  >
                    Lưu Phiếu
                  </button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { StorageService } from '../services/storage';
import { RepairStatus, RepairTicket, Customer, Organization } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip, Legend,
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip
} from 'recharts';
import { CheckCircle2, Clock, AlertCircle, Package, History, Loader2 } from 'lucide-react';
import { DeviceIcon } from '../components/DeviceIcon';

export const DashboardPage: React.FC = () => {
  const [stats, setStats] = useState({
    total: 0,
    received: 0,
    processing: 0,
    returned: 0
  });

  const [tickets, setTickets] = useState<RepairTicket[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [deviceStats, setDeviceStats] = useState<{name: string, value: number}[]>([]);

  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      const [loadedTickets, loadedCustomers, loadedOrgs] = await Promise.all([
        StorageService.getTickets(),
        StorageService.getCustomers(),
        StorageService.getOrganizations()
      ]);

      setTickets(loadedTickets);
      setCustomers(loadedCustomers);
      setOrganizations(loadedOrgs);

      // Calc Status Stats
      setStats({
        total: loadedTickets.length,
        received: loadedTickets.filter(t => t.status === RepairStatus.RECEIVED).length,
        processing: loadedTickets.filter(t => t.status === RepairStatus.PROCESSING).length,
        returned: loadedTickets.filter(t => t.status === RepairStatus.RETURNED).length,
      });

      // Calc Device Type Stats
      const typeCounts: Record<string, number> = {};
      loadedTickets.forEach(t => {
        typeCounts[t.deviceType] = (typeCounts[t.deviceType] || 0) + 1;
      });
      const deviceData = Object.entries(typeCounts).map(([name, value]) => ({ name, value }));
      setDeviceStats(deviceData);
      setIsLoading(false);
    };

    fetchData();
  }, []);

  const getCustomerName = (customerId: string) => {
    const c = customers.find(cus => cus.id === customerId);
    return c ? c.fullName : '---';
  };

  const getOrgName = (customerId: string) => {
    const c = customers.find(cus => cus.id === customerId);
    if (!c) return '';
    const org = organizations.find(o => o.id === c.organizationId);
    return org ? org.name : '';
  };

  // Data for Status Bar Chart
  const statusData = [
    { name: 'Đã nhận', value: stats.received, color: '#3b82f6' }, // Blue
    { name: 'Đang xử lý', value: stats.processing, color: '#f59e0b' }, // Amber
    { name: 'Đã trả', value: stats.returned, color: '#22c55e' }, // Green
  ];

  // Colors for Device Pie Chart
  const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8', '#82ca9d'];

  // Recent Tickets (Top 5 newest)
  const recentTickets = [...tickets]
    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    .slice(0, 5);

  if (isLoading) {
    return (
      <div className="flex h-[50vh] items-center justify-center">
        <Loader2 className="animate-spin text-blue-600" size={48} />
      </div>
    );
  }

  return (
    <div className="space-y-6">
       <div>
          <h1 className="text-2xl font-bold text-slate-900">Tổng quan Hệ thống</h1>
          <p className="text-slate-500">Báo cáo tình trạng và số liệu hoạt động</p>
        </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          title="Tổng phiếu" 
          value={stats.total} 
          icon={<Package className="text-slate-600" />} 
          bg="bg-slate-100" 
        />
        <StatCard 
          title="Mới tiếp nhận" 
          value={stats.received} 
          icon={<AlertCircle className="text-blue-600" />} 
          bg="bg-blue-50" 
          borderColor="border-blue-200"
        />
        <StatCard 
          title="Đang xử lý" 
          value={stats.processing} 
          icon={<Clock className="text-amber-600" />} 
          bg="bg-amber-50" 
          borderColor="border-amber-200"
        />
        <StatCard 
          title="Đã trả khách" 
          value={stats.returned} 
          icon={<CheckCircle2 className="text-green-600" />} 
          bg="bg-green-50" 
          borderColor="border-green-200"
        />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Status Bar Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 min-h-[350px]">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Thống kê theo Trạng thái</h3>
          {stats.total === 0 ? (
            <div className="h-64 flex items-center justify-center text-slate-400">Chưa có dữ liệu</div>
          ) : (
            <ResponsiveContainer width="100%" height={300}>
              <BarChart
                layout="vertical"
                data={statusData}
                margin={{ top: 5, right: 30, left: 40, bottom: 5 }}
              >
                <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                <XAxis type="number" allowDecimals={false} />
                <YAxis dataKey="name" type="category" width={80} tick={{fontSize: 12}} />
                <Tooltip cursor={{fill: 'transparent'}} />
                <Legend />
                <Bar dataKey="value" name="Số lượng" fill="#3b82f6" radius={[0, 4, 4, 0]}>
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>

        {/* Device Type Pie Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 min-h-[350px]">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Tỷ lệ Loại thiết bị</h3>
          {stats.total === 0 ? (
            <div className="h-64 flex items-center justify-center text-slate-400">Chưa có dữ liệu</div>
          ) : (
            <ResponsiveContainer width="100%" height={300}>
              <PieChart>
                <Pie
                  data={deviceStats}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                  label={({name, percent}) => `${name} ${(percent * 100).toFixed(0)}%`}
                >
                  {deviceStats.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>

      {/* Recent History Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-200 flex items-center justify-between bg-slate-50">
          <div className="flex items-center gap-2">
            <History className="text-slate-500" size={20} />
            <h3 className="text-lg font-semibold text-slate-800">Phiếu sửa chữa gần đây</h3>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-600 font-medium">
              <tr>
                <th className="px-6 py-3">Ngày nhận</th>
                <th className="px-6 py-3">Thiết bị</th>
                <th className="px-6 py-3">Khách hàng</th>
                <th className="px-6 py-3">Trạng thái</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {recentTickets.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-6 py-8 text-center text-slate-500">
                    Chưa có dữ liệu.
                  </td>
                </tr>
              ) : (
                recentTickets.map((t) => (
                  <tr key={t.id} className="hover:bg-slate-50">
                    <td className="px-6 py-4 font-medium text-slate-700">{t.receiveDate}</td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2 mb-0.5">
                        <DeviceIcon type={t.deviceType} size={16} className="text-slate-500" />
                        <span className="font-medium text-slate-900">{t.deviceType}</span>
                      </div>
                      {t.serialNumber && <span className="text-xs text-slate-500 pl-6 block">SN: {t.serialNumber}</span>}
                    </td>
                    <td className="px-6 py-4">
                      <span className="block text-slate-900">{getCustomerName(t.customerId)}</span>
                      <span className="text-xs text-slate-500">{getOrgName(t.customerId)}</span>
                    </td>
                    <td className="px-6 py-4">
                      <StatusBadge status={t.status} />
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, bg, borderColor = "border-transparent" }: any) => (
  <div className={`p-6 rounded-xl ${bg} border ${borderColor} transition-transform hover:scale-105 duration-200`}>
    <div className="flex items-center justify-between">
      <div>
        <p className="text-sm font-medium text-slate-500 mb-1">{title}</p>
        <p className="text-3xl font-bold text-slate-900">{value}</p>
      </div>
      <div className="p-3 bg-white/50 rounded-lg backdrop-blur-sm">
        {icon}
      </div>
    </div>
  </div>
);

const StatusBadge = ({ status }: { status: RepairStatus }) => {
  const colors = {
    [RepairStatus.RECEIVED]: 'bg-blue-100 text-blue-700',
    [RepairStatus.PROCESSING]: 'bg-amber-100 text-amber-700',
    [RepairStatus.RETURNED]: 'bg-green-100 text-green-700',
  };
  return (
    <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${colors[status]}`}>
      {status}
    </span>
  );
};

import React from 'react';
import { RepairTicket, RepairStatus, Customer, Organization } from '../types';
import { X, Calendar, CheckCircle2, AlertCircle, Clock, FileText } from 'lucide-react';
import { DeviceIcon } from './DeviceIcon';

interface HistoryModalProps {
  title: string;
  tickets: RepairTicket[];
  customers: Customer[];
  organizations?: Organization[]; // Added optional organization list for looking up names
  isOpen: boolean;
  onClose: () => void;
}

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  title, 
  tickets, 
  customers,
  organizations = [],
  isOpen, 
  onClose 
}) => {
  if (!isOpen) return null;

  const getCustomerName = (id: string) => {
    const c = customers.find(cus => cus.id === id);
    return c ? c.fullName : 'Unknown';
  };

  const getOrgName = (customerId: string) => {
    const c = customers.find(cus => cus.id === customerId);
    if (!c) return '';
    const org = organizations.find(o => o.id === c.organizationId);
    return org ? `(${org.name})` : '';
  };

  const statusColors = {
    [RepairStatus.RECEIVED]: 'bg-blue-100 text-blue-700',
    [RepairStatus.PROCESSING]: 'bg-amber-100 text-amber-700',
    [RepairStatus.RETURNED]: 'bg-green-100 text-green-700',
  };

  // Sort tickets by date descending (newest first)
  const sortedTickets = [...tickets].sort((a, b) => 
    new Date(b.receiveDate).getTime() - new Date(a.receiveDate).getTime()
  );

  return (
    <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl flex flex-col max-h-[85vh] animate-in fade-in zoom-in-95 duration-200">
        <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50 rounded-t-xl">
          <div className="flex items-center gap-2">
            <Clock className="text-blue-600" size={20} />
            <h3 className="font-semibold text-lg text-slate-800">{title}</h3>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6">
          {sortedTickets.length === 0 ? (
            <div className="text-center py-12 text-slate-500">
              <FileText size={48} className="mx-auto mb-3 text-slate-300" />
              <p>Không có lịch sử sửa chữa nào.</p>
            </div>
          ) : (
            <div className="space-y-6">
              {sortedTickets.map((ticket) => (
                <div key={ticket.id} className="relative pl-8 border-l-2 border-slate-200 last:border-0 pb-6 last:pb-0">
                  <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-white border-2 border-blue-500"></div>

                  <div className="bg-slate-50 rounded-lg p-4 border border-slate-200 hover:shadow-sm transition-shadow">
                    <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2 mb-2">
                      <div>
                        <span className="font-bold text-slate-900 mr-2">{ticket.receiveDate}</span>
                        <span className="text-sm text-slate-500 font-mono">#{ticket.id.slice(0, 8)}</span>
                      </div>
                      <span className={`px-2 py-0.5 rounded-full text-xs font-medium w-fit ${statusColors[ticket.status]}`}>
                        {ticket.status}
                      </span>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm mt-3">
                      <div>
                        <p className="text-xs text-slate-500 uppercase tracking-wide font-semibold mb-1">Thiết bị</p>
                        <div className="flex items-center gap-1.5 mb-1">
                          <DeviceIcon type={ticket.deviceType} size={14} className="text-slate-500" />
                          <p className="font-medium text-slate-800">{ticket.deviceType}</p>
                        </div>
                        {ticket.serialNumber && (
                           <p className="text-slate-500 text-xs">SN: {ticket.serialNumber}</p>
                        )}
                        <p className="text-slate-600 mt-1">{ticket.deviceCondition}</p>
                      </div>

                      <div>
                        <p className="text-xs text-slate-500 uppercase tracking-wide font-semibold mb-1">Khách hàng</p>
                        <p className="text-slate-800">
                          {getCustomerName(ticket.customerId)} <span className="text-slate-500 text-xs">{getOrgName(ticket.customerId)}</span>
                        </p>
                      </div>
                    </div>

                    {ticket.status === RepairStatus.RETURNED && (
                      <div className="mt-3 pt-3 border-t border-slate-200">
                        <div className="flex items-start gap-2">
                          <CheckCircle2 size={16} className="text-green-600 mt-0.5" />
                          <div className="text-sm">
                            <span className="font-medium text-slate-900">Đã trả ngày {ticket.returnDate}</span>
                            <span className="text-slate-500"> qua {ticket.shippingMethod}</span>
                            {ticket.returnNote && (
                              <p className="text-slate-600 mt-1 italic">"{ticket.returnNote}"</p>
                            )}
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="px-6 py-4 border-t border-slate-200 bg-slate-50 rounded-b-xl text-right">
          <button 
            onClick={onClose}
            className="px-4 py-2 bg-white border border-slate-300 text-slate-700 hover:bg-slate-100 rounded-lg font-medium text-sm transition-colors"
          >
            Đóng
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Customer, RepairTicket, DeviceType, RepairStatus, ShippingMethod, Organization } from '../types';
import { StorageService } from '../services/storage';
import { Plus, Search, Filter, AlertCircle, CheckCircle2, Clock, Truck, ChevronRight, X, History, Download, ChevronLeft, Loader2, Trash2 } from 'lucide-react';
import { HistoryModal } from '../components/HistoryModal';
import { DeviceIcon } from '../components/DeviceIcon';

export const RepairsPage: React.FC = () => {
  const [tickets, setTickets] = useState<RepairTicket[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const ITEMS_PER_PAGE = 10;

  // History State
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [historyTitle, setHistoryTitle] = useState('');
  const [historyTickets, setHistoryTickets] = useState<RepairTicket[]>([]);

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<RepairTicket>>({});

  const fetchData = async () => {
    setIsLoading(true);
    const [t, c, o] = await Promise.all([
      StorageService.getTickets(),
      StorageService.getCustomers(),
      StorageService.getOrganizations()
    ]);
    setTickets(t);
    setCustomers(c);
    setOrganizations(o);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Reset page when filter changes
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter]);

  const getCustomer = (id: string) => customers.find(c => c.id === id);

  const getOrgName = (customerId: string) => {
    const customer = getCustomer(customerId);
    if (!customer) return '';
    const org = organizations.find(o => o.id === customer.organizationId);
    return org ? org.name : 'Unknown Org';
  }

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation(); // Prevent opening the modal
    if (window.confirm('Bạn có chắc chắn muốn xóa phiếu sửa chữa này không?')) {
      try {
        await StorageService.deleteTicket(id);
        await fetchData();
        if (isModalOpen) closeModal();
      } catch (err) {
        console.error(err);
        alert('Có lỗi xảy ra khi xóa phiếu.');
      }
    }
  };

  // --- EXPORT FUNCTIONALITY ---
  const handleExport = () => {
    // 1. Prepare Header
    const headers = [
      "Mã Phiếu", 
      "Ngày Nhận", 
      "Tên Khách Hàng", 
      "Đơn Vị", 
      "Số Điện Thoại",
      "Loại Thiết Bị", 
      "Số Serial", 
      "Tình Trạng", 
      "Trạng Thái", 
      "Ngày Trả", 
      "Vận Chuyển", 
      "Ghi Chú"
    ];

    // 2. Prepare Rows
    const rows = tickets.map(t => {
      const c = getCustomer(t.customerId);
      const org = getOrgName(t.customerId);
      return [
        t.id.slice(0, 8),
        t.receiveDate,
        c ? c.fullName : '',
        org,
        c ? `'${c.phone}` : '', // Add quote to prevent Excel auto-formatting as number
        t.deviceType,
        t.serialNumber || '',
        t.deviceCondition,
        t.status,
        t.returnDate || '',
        t.shippingMethod || '',
        t.returnNote || ''
      ].map(field => `"${field}"`).join(','); // Quote fields and join with comma
    });

    // 3. Combine with BOM for UTF-8 support
    const csvContent = "\uFEFF" + [headers.join(','), ...rows].join('\n');

    // 4. Create Blob and Link
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `Bao_cao_sua_chua_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSave = async () => {
    if (!formData.customerId || !formData.deviceType || !formData.receiveDate) {
      alert('Vui lòng điền đầy đủ thông tin bắt buộc');
      return;
    }

    if (formData.status === RepairStatus.RETURNED) {
      if (!formData.returnDate || !formData.shippingMethod) {
        alert('Khi trạng thái là "Đã trả", vui lòng nhập ngày trả và đơn vị vận chuyển.');
        return;
      }
    }

    const newTicket: RepairTicket = {
      id: editingId || crypto.randomUUID(),
      customerId: formData.customerId,
      deviceType: formData.deviceType as DeviceType,
      serialNumber: formData.serialNumber,
      deviceCondition: formData.deviceCondition || 'Không rõ',
      receiveDate: formData.receiveDate,
      status: formData.status || RepairStatus.RECEIVED,

      returnDate: formData.returnDate,
      returnNote: formData.returnNote,
      shippingMethod: formData.shippingMethod as ShippingMethod,

      createdAt: editingId ? (tickets.find(t => t.id === editingId)?.createdAt || Date.now()) : Date.now(),
      updatedAt: Date.now()
    };

    try {
      if (editingId) {
        await StorageService.updateTicket(newTicket);
      } else {
        await StorageService.addTicket(newTicket);
      }
      await fetchData();
      closeModal();
    } catch (e) {
      console.error(e);
      alert('Lỗi khi lưu phiếu sửa chữa');
    }
  };

  const openModal = (ticket?: RepairTicket) => {
    if (ticket) {
      setEditingId(ticket.id);
      setFormData({ ...ticket });
    } else {
      setEditingId(null);
      setFormData({
        status: RepairStatus.RECEIVED,
        receiveDate: new Date().toISOString().split('T')[0],
        deviceType: DeviceType.CODEC,
        deviceCondition: '',
        serialNumber: ''
      });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const openDeviceHistory = (e: React.MouseEvent, ticket: RepairTicket) => {
    e.stopPropagation(); 
    let matches: RepairTicket[] = [];
    let title = '';

    if (ticket.serialNumber) {
      matches = tickets.filter(t => t.serialNumber === ticket.serialNumber);
      title = `Lịch sử thiết bị: ${ticket.deviceType} - SN: ${ticket.serialNumber}`;
    } else {
      matches = tickets.filter(t => t.customerId === ticket.customerId && t.deviceType === ticket.deviceType);
      const c = getCustomer(ticket.customerId);
      title = `Lịch sử: ${ticket.deviceType} của ${c?.fullName || 'Khách hàng'}`;
    }

    setHistoryTickets(matches);
    setHistoryTitle(title);
    setIsHistoryOpen(true);
  };

  const statusColors = {
    [RepairStatus.RECEIVED]: 'bg-blue-100 text-blue-700 border-blue-200',
    [RepairStatus.PROCESSING]: 'bg-amber-100 text-amber-700 border-amber-200',
    [RepairStatus.RETURNED]: 'bg-green-100 text-green-700 border-green-200',
  };

  const filteredTickets = tickets.filter(t => {
    const customer = getCustomer(t.customerId);
    const orgName = getOrgName(t.customerId);

    const matchesSearch = 
      customer?.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      orgName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      t.deviceType.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (t.serialNumber && t.serialNumber.toLowerCase().includes(searchTerm.toLowerCase())) ||
      t.id.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === 'ALL' || t.status === statusFilter;

    return matchesSearch && matchesStatus;
  });

  // Pagination Logic
  const totalPages = Math.ceil(filteredTickets.length / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const paginatedTickets = filteredTickets.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Quản lý Sửa chữa</h1>
          <p className="text-slate-500">Theo dõi quy trình nhận và trả thiết bị</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleExport}
            className="flex items-center gap-2 bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-4 py-2 rounded-lg transition-colors shadow-sm"
          >
            <Download size={18} />
            <span>Xuất Excel</span>
          </button>
          <button 
            onClick={() => openModal()}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors shadow-sm"
          >
            <Plus size={18} />
            <span>Tạo phiếu mới</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
        {/* Filters */}
        <div className="p-4 border-b border-slate-200 bg-slate-50 flex flex-col md:flex-row gap-4 justify-between">
          <div className="relative max-w-md w-full">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm theo Serial, khách hàng, đơn vị..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div className="flex items-center gap-2">
            <Filter size={18} className="text-slate-500" />
            <select 
              className="px-3 py-2 border border-slate-300 rounded-lg bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
            >
              <option value="ALL">Tất cả trạng thái</option>
              {Object.values(RepairStatus).map(s => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto min-h-[400px]">
          {isLoading ? (
             <div className="flex justify-center py-12">
               <Loader2 className="animate-spin text-blue-600" size={32} />
             </div>
          ) : (
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-600 font-medium">
              <tr>
                <th className="px-6 py-3">Mã phiếu / Ngày nhận</th>
                <th className="px-6 py-3">Khách hàng</th>
                <th className="px-6 py-3">Thiết bị</th>
                <th className="px-6 py-3">Trạng thái</th>
                <th className="px-6 py-3">Ngày trả / Vận chuyển</th>
                <th className="px-6 py-3 text-right">Thao tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {paginatedTickets.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-500 flex flex-col items-center justify-center">
                    <WrenchIconPlaceholder />
                    <span className="mt-2">Chưa có phiếu sửa chữa nào.</span>
                  </td>
                </tr>
              ) : (
                paginatedTickets.map((ticket) => {
                  const customer = getCustomer(ticket.customerId);
                  const orgName = getOrgName(ticket.customerId);

                  return (
                    <tr key={ticket.id} className="hover:bg-slate-50 transition-colors group cursor-pointer" onClick={() => openModal(ticket)}>
                      {/* Cột 1: Mã + Ngày Nhận */}
                      <td className="px-6 py-4">
                        <div className="font-mono text-xs text-slate-400">#{ticket.id.slice(0, 8)}</div>
                        <div className="font-medium text-slate-900 mt-1 flex items-center gap-1">
                           <Clock size={12} className="text-blue-500"/> {ticket.receiveDate}
                        </div>
                      </td>

                      {/* Cột 2: Khách Hàng */}
                      <td className="px-6 py-4">
                        <div className="font-semibold text-slate-900">{customer?.fullName || 'Unknown'}</div>
                        <div className="text-slate-500 text-xs mt-1 font-medium text-blue-600">{orgName}</div>
                      </td>

                      {/* Cột 3: Thiết bị */}
                      <td className="px-6 py-4">
                        <div className="flex flex-col">
                           <span className="inline-flex items-center gap-1.5 px-2 py-1 rounded bg-slate-100 text-slate-700 border border-slate-200 text-xs font-medium w-fit mb-1">
                            <DeviceIcon type={ticket.deviceType} size={14} className="text-slate-500" />
                            {ticket.deviceType}
                          </span>
                          {ticket.serialNumber && (
                             <span className="text-xs font-mono text-slate-600 bg-slate-50 px-1 rounded border border-slate-100 w-fit">
                              SN: {ticket.serialNumber}
                            </span>
                          )}
                          <div className="text-slate-500 text-xs mt-1 max-w-[150px] truncate" title={ticket.deviceCondition}>
                            {ticket.deviceCondition}
                          </div>
                        </div>
                      </td>

                      {/* Cột 4: Trạng Thái */}
                      <td className="px-6 py-4">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border ${statusColors[ticket.status]}`}>
                          {ticket.status}
                        </span>
                      </td>

                      {/* Cột 5: Ngày Trả / Vận Chuyển (Explicit) */}
                      <td className="px-6 py-4">
                        {ticket.status === RepairStatus.RETURNED ? (
                          <div className="text-xs">
                             <div className="flex items-center gap-1 font-medium text-green-700 mb-1">
                                <CheckCircle2 size={12} />
                                {ticket.returnDate}
                             </div>
                            <div className="flex items-center gap-1 text-slate-600">
                              <Truck size={12} />
                              {ticket.shippingMethod}
                            </div>
                          </div>
                        ) : (
                          <span className="text-slate-400 text-xs italic">---</span>
                        )}
                      </td>

                      {/* Cột 6: Thao tác */}
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end items-center gap-2">
                          <button 
                            onClick={(e) => openDeviceHistory(e, ticket)}
                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                            title="Xem lịch sử thiết bị"
                          >
                            <History size={18} />
                          </button>
                          <button 
                            onClick={(e) => handleDelete(e, ticket.id)}
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                            title="Xóa phiếu"
                          >
                            <Trash2 size={18} />
                          </button>
                          <ChevronRight className="text-slate-300 group-hover:text-blue-500 transition-colors" size={20} />
                        </div>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
          )}
        </div>

        {/* Pagination Footer */}
        {filteredTickets.length > 0 && (
          <div className="px-6 py-4 border-t border-slate-200 bg-slate-50 flex items-center justify-between">
            <div className="text-sm text-slate-500">
              Hiển thị <span className="font-medium">{startIndex + 1}</span> đến <span className="font-medium">{Math.min(startIndex + ITEMS_PER_PAGE, filteredTickets.length)}</span> trong tổng số <span className="font-medium">{filteredTickets.length}</span> phiếu
            </div>
            <div className="flex items-center gap-2">
              <button 
                onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                disabled={currentPage === 1}
                className="p-2 border border-slate-300 rounded-lg hover:bg-white disabled:opacity-50 disabled:cursor-not-allowed bg-white text-slate-600 transition-colors"
              >
                <ChevronLeft size={16} />
              </button>
              <div className="px-4 py-1.5 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700">
                Trang {currentPage} / {totalPages || 1}
              </div>
              <button 
                onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                disabled={currentPage === totalPages || totalPages === 0}
                className="p-2 border border-slate-300 rounded-lg hover:bg-white disabled:opacity-50 disabled:cursor-not-allowed bg-white text-slate-600 transition-colors"
              >
                <ChevronRight size={16} />
              </button>
            </div>
          </div>
        )}
      </div>

      <HistoryModal 
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        tickets={historyTickets}
        customers={customers}
        organizations={organizations}
        title={historyTitle}
      />

      {/* Modal Form */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl my-8 flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50 rounded-t-xl sticky top-0">
              <h3 className="font-semibold text-lg text-slate-800">
                {editingId ? 'Cập nhật Phiếu Sửa Chữa' : 'Tạo Phiếu Mới'}
              </h3>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <div className="p-6 overflow-y-auto space-y-6">
              {/* Customer Section */}
              <div className="space-y-4">
                <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wider border-b pb-2">Thông tin nhận</h4>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-sm font-medium text-slate-700">Khách hàng <span className="text-red-500">*</span></label>
                    <select 
