        >
          <Plus size={18} />
          <span>Thêm Khách hàng</span>
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-red-100 overflow-hidden">
        <div className="p-4 border-b border-red-100 bg-red-50/30">
