              </tr>
            </thead>
            <tbody className="divide-y divide-red-100">
              {paginatedTickets.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-500 italic">
                    Chưa có phiếu gửi hàng nào.
