      try {
        await StorageService.deleteOrganization(id);
        await fetchData();
      } catch (error: any) {
        console.error(error);
        if (error.code === '23503') {
          alert('KHÔNG THỂ XÓA: Đơn vị này hiện có dữ liệu liên quan. Vui lòng xóa Khách hàng thuộc đơn vị này trước.');
