                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Customer, RepairTicket, Organization } from '../types';
import { StorageService } from '../services/storage';
import { Plus, Search, MapPin, Phone, Building2, Trash2, Edit2, X, History, Loader2, AlertTriangle } from 'lucide-react';
import { HistoryModal } from '../components/HistoryModal';

export const CustomersPage: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [tickets, setTickets] = useState<RepairTicket[]>([]); 
  const [isLoading, setIsLoading] = useState(true);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // History Modal State
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [historyCustomer, setHistoryCustomer] = useState<Customer | null>(null);

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Customer>>({
    fullName: '',
    organizationId: '',
    phone: '',
    address: ''
  });

  const fetchData = async () => {
    setIsLoading(true);
    const [custs, orgs, tcks] = await Promise.all([
      StorageService.getCustomers(),
      StorageService.getOrganizations(),
      StorageService.getTickets()
    ]);
    setCustomers(custs);
    setOrganizations(orgs);
    setTickets(tcks);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const getOrgName = (orgId: string) => {
    return organizations.find(o => o.id === orgId)?.name || '---';
  };

  const handleSave = async () => {
    if (!formData.fullName || !formData.organizationId) {
      alert('Vui lòng nhập tên và chọn đơn vị');
      return;
    }

    // KIỂM TRÙNG SỐ ĐIỆN THOẠI (Chỉ kiểm tra khi thêm mới hoặc đổi số điện thoại)
    const phoneTrimmed = formData.phone?.trim();
    if (phoneTrimmed) {
      const duplicate = customers.find(c => 
        c.phone.trim() === phoneTrimmed && c.id !== editingId
      );
      if (duplicate) {
        alert(`LỖI: Số điện thoại ${phoneTrimmed} đã được đăng ký cho khách hàng "${duplicate.fullName}" tại đơn vị "${getOrgName(duplicate.organizationId)}".`);
        return;
      }
    }

    const newCustomer: Customer = {
      id: editingId || crypto.randomUUID(),
      fullName: formData.fullName!.trim(),
      organizationId: formData.organizationId!,
      phone: phoneTrimmed || '',
      address: formData.address?.trim() || '',
      createdAt: editingId ? (customers.find(c => c.id === editingId)?.createdAt || Date.now()) : Date.now()
    };

    try {
      if (editingId) {
        await StorageService.updateCustomer(newCustomer);
      } else {
        await StorageService.addCustomer(newCustomer);
      }
      await fetchData();
      closeModal();
    } catch (e) {
      console.error(e);
      alert('Lỗi khi lưu khách hàng');
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa khách hàng này? Lưu ý: Mọi phiếu sửa chữa của khách hàng này cũng sẽ bị xóa.')) {
      try {
        await StorageService.deleteCustomer(id);
        await fetchData();
      } catch (error: any) {
        console.error(error);
        alert('Có lỗi xảy ra khi xóa khách hàng.');
      }
    }
  };

  const openModal = (customer?: Customer) => {
    if (customer) {
      setEditingId(customer.id);
      setFormData({ ...customer });
    } else {
      setEditingId(null);
      setFormData({ fullName: '', organizationId: '', phone: '', address: '' });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({ fullName: '', organizationId: '', phone: '', address: '' });
  };

  const openHistory = (customer: Customer) => {
    setHistoryCustomer(customer);
    setIsHistoryOpen(true);
  };

  const filteredCustomers = customers.filter(c => 
    c.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    getOrgName(c.organizationId).toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.phone.includes(searchTerm)
  );

  const customerTickets = historyCustomer 
    ? tickets.filter(t => t.customerId === historyCustomer.id) 
    : [];

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Quản lý Khách hàng</h1>
          <p className="text-slate-500">Quản lý danh sách người liên hệ tại các đơn vị</p>
        </div>
        <button 
          onClick={() => openModal()}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl transition-all shadow-lg shadow-blue-600/20 font-bold"
        >
          <Plus size={18} />
          <span>Thêm Khách hàng mới</span>
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50/50">
          <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm tên, đơn vị, số điện thoại..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
            />
          </div>
        </div>

        <div className="overflow-x-auto min-h-[300px]">
          {isLoading ? (
            <div className="flex justify-center py-12">
               <Loader2 className="animate-spin text-blue-600" size={32} />
            </div>
          ) : (
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-50 text-slate-500 font-bold uppercase tracking-wider text-[11px] border-b border-slate-200">
                <tr>
                  <th className="px-6 py-4">Họ và Tên</th>
                  <th className="px-6 py-4">Đơn vị</th>
                  <th className="px-6 py-4">Số điện thoại</th>
                  <th className="px-6 py-4">Địa chỉ</th>
                  <th className="px-6 py-4 text-right">Thao tác</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredCustomers.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="px-6 py-20 text-center text-slate-400">
                      Chưa có dữ liệu khách hàng.
                    </td>
                  </tr>
                ) : (
                  filteredCustomers.map((customer) => (
                    <tr key={customer.id} className="hover:bg-blue-50/30 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="font-bold text-slate-900">{customer.fullName}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="inline-flex items-center gap-1.5 px-2 py-0.5 rounded-lg bg-blue-50 text-blue-600 border border-blue-100 text-[11px] font-bold uppercase">
                          <Building2 size={12} />
                          {getOrgName(customer.organizationId)}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2 text-slate-600 font-medium">
                          <Phone size={14} className="text-slate-400" />
                          {customer.phone || '---'}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2 text-slate-500 text-xs max-w-xs truncate">
                          <MapPin size={14} className="text-slate-400" />
                          {customer.address || '---'}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-1">
                          <button 
                            onClick={() => openHistory(customer)}
                            className="p-2 text-amber-500 hover:bg-amber-50 rounded-lg transition-all"
                            title="Lịch sử sửa chữa"
                          >
                            <History size={18} />
                          </button>
                          <button 
                            onClick={() => openModal(customer)}
                            className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg transition-all"
                            title="Chỉnh sửa"
                          >
                            <Edit2 size={18} />
                          </button>
                          <button 
                            onClick={() => handleDelete(customer.id)}
                            className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition-all"
                            title="Xóa"
                          >
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          )}
        </div>
      </div>

      <HistoryModal 
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        tickets={customerTickets}
        customers={customers}
        organizations={organizations}
        title={`Lịch sử: ${historyCustomer?.fullName}`}
      />

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-white/20 animate-in fade-in zoom-in-95 duration-200">
            <div className="px-6 py-5 border-b border-slate-200 flex justify-between items-center bg-slate-50">
              <h3 className="font-bold text-lg text-slate-800">
                {editingId ? 'Cập nhật thông tin Khách hàng' : 'Thêm Khách hàng mới'}
              </h3>
              <button onClick={closeModal} className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-200 rounded-full transition-colors">
                <X size={20} />
              </button>
            </div>

            <div className="p-6 space-y-5">
              <div className="space-y-1.5">
                 <label className="text-[11px] font-bold text-slate-500 uppercase ml-1">Đơn vị chủ quản *</label>
                 <select
                   className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white shadow-sm"
                   value={formData.organizationId}
                   onChange={(e) => setFormData({...formData, organizationId: e.target.value})}
                 >
                    <option value="">-- Chọn đơn vị --</option>
                    {organizations.map(org => (
                      <option key={org.id} value={org.id}>{org.name}</option>
                    ))}
                 </select>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[11px] font-bold text-slate-500 uppercase ml-1">Họ và tên *</label>
                  <input 
                    type="text" 
                    className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white shadow-sm"
                    value={formData.fullName}
                    onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                    placeholder="Nguyễn Văn A"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[11px] font-bold text-slate-500 uppercase ml-1">Số điện thoại</label>
                  <input 
                    type="text" 
                    className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white shadow-sm"
                    value={formData.phone}
                    onChange={(e) => setFormData({...formData, phone: e.target.value})}
                    placeholder="0987..."
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-[11px] font-bold text-slate-500 uppercase ml-1">Địa chỉ liên hệ</label>
                <textarea 
                  className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white shadow-sm"
                  rows={3}
                  value={formData.address}
                  onChange={(e) => setFormData({...formData, address: e.target.value})}
                  placeholder="Số nhà, đường, phường/xã, quận/huyện..."
                />
              </div>
            </div>

            <div className="px-6 py-5 bg-slate-50 border-t border-slate-200 flex justify-end gap-3">
              <button 
                onClick={closeModal}
                className="px-5 py-2.5 text-slate-600 hover:bg-slate-200 rounded-xl transition-all font-bold text-sm"
              >
                Hủy bỏ
              </button>
              <button 
                onClick={handleSave}
                className="px-8 py-2.5 bg-blue-600 text-white hover:bg-blue-700 rounded-xl transition-all font-bold text-sm shadow-xl shadow-blue-600/20 active:scale-95"
              >
                Lưu thông tin
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Customer, RepairTicket, DeviceType, RepairStatus, ShippingMethod, Organization } from '../types';
import { StorageService } from '../services/storage';
import { Plus, Search, Filter, AlertCircle, CheckCircle2, Clock, Truck, ChevronRight, X, History, Download, ChevronLeft, Loader2, Trash2, UserPlus, UserCheck, Barcode, Eye } from 'lucide-react';
import { HistoryModal } from '../components/HistoryModal';
import { DeviceIcon } from '../components/DeviceIcon';
import { ShippingStatusBadge } from '../components/ShippingStatusBadge';

export const RepairsPage: React.FC = () => {
  const [tickets, setTickets] = useState<RepairTicket[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  const [currentPage, setCurrentPage] = useState(1);
  const ITEMS_PER_PAGE = 15;

  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [historyTitle, setHistoryTitle] = useState('');
  const [historyTickets, setHistoryTickets] = useState<RepairTicket[]>([]);

  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<RepairTicket>>({});

  const [isAddingNewCustomer, setIsAddingNewCustomer] = useState(false);
  const [newCustomerData, setNewCustomerData] = useState<Partial<Customer>>({
    fullName: '',
    organizationId: '',
    phone: '',
    address: ''
  });

  const fetchData = async () => {
    setIsLoading(true);
    const [t, c, o] = await Promise.all([
      StorageService.getTickets(),
      StorageService.getCustomers(),
      StorageService.getOrganizations()
    ]);
    setTickets(t);
    setCustomers(c);
    setOrganizations(o);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter]);

  const getCustomer = (id: string) => customers.find(c => c.id === id);

  const getOrgName = (customerId: string) => {
    const customer = getCustomer(customerId);
    if (!customer) return '';
    const org = organizations.find(o => o.id === customer.organizationId);
    return org ? org.name : 'Unknown Org';
  }

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('Bạn có chắc chắn muốn xóa phiếu sửa chữa này không?')) {
      try {
        await StorageService.deleteTicket(id);
        await fetchData();
        if (isModalOpen) closeModal();
      } catch (err) {
        console.error(err);
        alert('Có lỗi xảy ra khi xóa phiếu.');
      }
    }
  };

  const handleExport = () => {
    const headers = ["Mã Phiếu", "Ngày Nhận", "Tên Khách Hàng", "Đơn Vị", "Số Điện Thoại", "Loại Thiết Bị", "Số Serial", "Tình Trạng", "Trạng Thái", "Ngày Trả", "Vận Chuyển", "Mã Vận Đơn", "Ghi Chú"];
    const rows = tickets.map(t => {
      const c = getCustomer(t.customerId);
      const org = getOrgName(t.customerId);
      return [
        t.id.slice(0, 8), t.receiveDate, c ? c.fullName : '', org, c ? `'${c.phone}` : '', t.deviceType, t.serialNumber || '', t.deviceCondition, t.status, t.returnDate || '', t.shippingMethod || '', t.trackingNumber || '', t.returnNote || ''
      ].map(field => `"${field}"`).join(',');
    });
    const csvContent = "\uFEFF" + [headers.join(','), ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `Bao_cao_sua_chua_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSave = async () => {
    let finalCustomerId = formData.customerId;

    // XỬ LÝ KHÁCH HÀNG MỚI (VỚI KIỂM TRA TRÙNG SỐ ĐIỆN THOẠI)
    if (isAddingNewCustomer) {
      if (!newCustomerData.fullName || !newCustomerData.organizationId) {
        alert('Vui lòng nhập tên khách hàng và chọn đơn vị cho khách hàng mới');
        return;
      }

      const phoneTrimmed = newCustomerData.phone?.trim();
      if (phoneTrimmed) {
        const existing = customers.find(c => c.phone.trim() === phoneTrimmed);
        if (existing) {
          const useExisting = window.confirm(
            `PHÁT HIỆN TRÙNG LẶP: Số điện thoại ${phoneTrimmed} đã tồn tại với tên "${existing.fullName}". \n\nBạn có muốn sử dụng khách hàng này thay vì tạo mới không?`
          );
          if (useExisting) {
            finalCustomerId = existing.id;
            setIsAddingNewCustomer(false);
          } else {
            return; // Dừng lại để người dùng đổi số điện thoại
          }
        }
      }

      // Nếu vẫn là khách hàng mới (không trùng hoặc người dùng chấp nhận tiếp tục)
      if (isAddingNewCustomer && !finalCustomerId) {
        const newCustId = crypto.randomUUID();
        const customerToSave: Customer = {
          id: newCustId,
          fullName: newCustomerData.fullName!.trim(),
          organizationId: newCustomerData.organizationId!,
          phone: phoneTrimmed || '',
          address: newCustomerData.address?.trim() || '',
          createdAt: Date.now()
        };

        try {
          await StorageService.addCustomer(customerToSave);
          finalCustomerId = newCustId;
          // Cập nhật local state để hiển thị ngay
          setCustomers(prev => [customerToSave, ...prev]);
        } catch (e) {
          console.error(e);
          alert('Lỗi khi lưu thông tin khách hàng mới');
          return;
        }
      }
    }

    if (!finalCustomerId || !formData.deviceType || !formData.receiveDate) {
      alert('Vui lòng chọn khách hàng và điền đầy đủ thông tin thiết bị');
      return;
    }

    if (formData.status === RepairStatus.RETURNED) {
      if (!formData.returnDate || !formData.shippingMethod) {
        alert('Khi trạng thái là "Đã trả", vui lòng nhập ngày trả và đơn vị vận chuyển.');
        return;
      }
    }

    const newTicket: RepairTicket = {
      id: editingId || crypto.randomUUID(),
      customerId: finalCustomerId,
      deviceType: formData.deviceType as DeviceType,
      serialNumber: formData.serialNumber?.trim() || '',
      deviceCondition: formData.deviceCondition || 'Không rõ',
      receiveDate: formData.receiveDate,
      status: formData.status || RepairStatus.RECEIVED,
      returnDate: formData.returnDate,
      returnNote: formData.returnNote,
      shippingMethod: formData.shippingMethod as ShippingMethod,
      trackingNumber: formData.trackingNumber?.trim(),
      createdAt: editingId ? (tickets.find(t => t.id === editingId)?.createdAt || Date.now()) : Date.now(),
      updatedAt: Date.now()
    };

    try {
      if (editingId) {
        await StorageService.updateTicket(newTicket);
      } else {
        await StorageService.addTicket(newTicket);
      }
      await fetchData();
      closeModal();
    } catch (e) {
      console.error(e);
      alert('Lỗi khi lưu phiếu sửa chữa');
    }
  };

  const openModal = (ticket?: RepairTicket) => {
    setIsAddingNewCustomer(false);
    setNewCustomerData({ fullName: '', organizationId: '', phone: '', address: '' });

    if (ticket) {
      setEditingId(ticket.id);
      setFormData({ ...ticket });
    } else {
      setEditingId(null);
      setFormData({
        status: RepairStatus.RECEIVED,
        receiveDate: new Date().toISOString().split('T')[0],
        deviceType: DeviceType.CODEC,
        deviceCondition: '',
        serialNumber: ''
      });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const openDeviceHistory = (e: React.MouseEvent, ticket: RepairTicket) => {
    e.stopPropagation(); 
    let matches: RepairTicket[] = [];
    let title = '';
    if (ticket.serialNumber) {
      matches = tickets.filter(t => t.serialNumber === ticket.serialNumber);
      title = `Lịch sử thiết bị: ${ticket.deviceType} - SN: ${ticket.serialNumber}`;
    } else {
      matches = tickets.filter(t => t.customerId === ticket.customerId && t.deviceType === ticket.deviceType);
      const c = getCustomer(ticket.customerId);
      title = `Lịch sử: ${ticket.deviceType} của ${c?.fullName || 'Khách hàng'}`;
    }
    setHistoryTickets(matches);
    setHistoryTitle(title);
    setIsHistoryOpen(true);
  };

  const statusColors = {
    [RepairStatus.RECEIVED]: 'bg-blue-100 text-blue-700 border-blue-200',
    [RepairStatus.PROCESSING]: 'bg-amber-100 text-amber-700 border-amber-200',
    [RepairStatus.RETURNED]: 'bg-green-100 text-green-700 border-green-200',
  };

  const filteredTickets = tickets.filter(t => {
    const customer = getCustomer(t.customerId);
    const orgName = getOrgName(t.customerId);
    const matchesSearch = customer?.fullName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          orgName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.deviceType.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          (t.serialNumber && t.serialNumber.toLowerCase().includes(searchTerm.toLowerCase())) || 
                          t.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          (t.trackingNumber && t.trackingNumber.toLowerCase().includes(searchTerm.toLowerCase()));
    const matchesStatus = statusFilter === 'ALL' || t.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const totalPages = Math.ceil(filteredTickets.length / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const paginatedTickets = filteredTickets.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  // Helper for Modal Preview
  const currentPreviewCustomer = isAddingNewCustomer 
    ? newCustomerData.fullName || 'Đang nhập tên...' 
