                            {customers.map(c => (<option key={c.id} value={c.id}>{c.fullName} - {getOrgName(c.id)}</option>))}
                          </select>
                        </div>
                        <div className="space-y-1">
                          <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Ngày tiếp nhận *</label>
